 12→// fakeCommandBuilder returns a commandBuilder that runs a helper process
 13→// instead of the real claude binary. The helper process behaviour is
 14→// controlled by the env var KILN_TEST_HELPER_MODE.
 15→func fakeCommandBuilder(mode string) func(string) *exec.Cmd {
 16→	return func(prompt string) *exec.Cmd {
 17→		cmd := exec.Command(os.Args[0], "-test.run=TestHelperProcess", "--", prompt)
 18→		cmd.Env = append(os.Environ(), "KILN_TEST_HELPER_MODE="+mode)
 19→		return cmd
 20→	}
 21→}
 22→
 23→// TestHelperProcess is invoked as a subprocess by the fake command builder.
 24→// It is not a real test — the guard at the top prevents it from running
 25→// as part of the normal test suite.
 26→func TestHelperProcess(t *testing.T) {
 27→	mode := os.Getenv("KILN_TEST_HELPER_MODE")
 28→	if mode == "" {
 29→		return // not invoked as a helper
 30→	}
 31→
 32→	switch mode {
 33→	case "success":
 34→		// Echo the prompt back as fake stream-json output
 35→		args := os.Args
 36→		for i, a := range args {
 37→			if a == "--" {
 38→				if i+1 < len(args) {
 39→					os.Stdout.WriteString(`{"type":"assistant","content":"` + args[i+1] + `"}` + "\n")
 40→				}
 41→				break
 42→			}
 43→		}
 44→		os.Exit(0)
 45→	case "fail":
 46→		os.Stderr.WriteString("error: something went wrong\n")
 47→		os.Exit(1)
 48→	default:
 49→		os.Stderr.WriteString("unknown helper mode\n")
 50→		os.Exit(2)
 51→	}
 52→}
