 54→func TestRunExec_MissingTaskID(t *testing.T) {
 55→	err := runExec([]string{"--prompt-file", "some.md"}, &bytes.Buffer{})
 56→	if err == nil {
 57→		t.Fatal("expected error for missing --task-id")
 58→	}
 59→	if !strings.Contains(err.Error(), "--task-id is required") {
 60→		t.Fatalf("unexpected error: %v", err)
 61→	}
 62→}
