 87→func TestRunExec_Success(t *testing.T) {
 88→	// Save and restore the original commandBuilder
 89→	origBuilder := commandBuilder
 90→	t.Cleanup(func() { commandBuilder = origBuilder })
 91→	commandBuilder = fakeCommandBuilder("success")
 92→
 93→	// Set up temp directory as working dir so .kiln/logs is created there
 94→	tmpDir := t.TempDir()
 95→	origDir, _ := os.Getwd()
 96→	t.Cleanup(func() { os.Chdir(origDir) })
 97→	os.Chdir(tmpDir)
 98→
 99→	// Create a prompt file
100→	promptPath := filepath.Join(tmpDir, "prompt.md")
101→	os.WriteFile(promptPath, []byte("hello world"), 0o644)
102→
103→	var stdout bytes.Buffer
104→	err := runExec([]string{
105→		"--task-id", "test-01",
