107→	}, &stdout)
108→	if err != nil {
109→		t.Fatalf("unexpected error: %v", err)
110→	}
111→
112→	// Verify stdout received output
113→	if !strings.Contains(stdout.String(), "hello world") {
114→		t.Errorf("stdout missing prompt echo, got: %s", stdout.String())
115→	}
116→
117→	// Verify log file was created and contains output
118→	logPath := filepath.Join(tmpDir, ".kiln", "logs", "test-01.json")
119→	logData, err := os.ReadFile(logPath)
120→	if err != nil {
121→		t.Fatalf("failed to read log file: %v", err)
122→	}
123→	if !strings.Contains(string(logData), "hello world") {
124→		t.Errorf("log file missing prompt echo, got: %s", string(logData))
125→	}
126→}
